def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 8):
            if ratio < 0.1 * j:
                score += (8 - j) ** 2 * np.exp(-ratio * j)
            else:
                partial = (ratio ** (j / 2)) * np.log1p(j)
                if j % 2 == 0:
                    partial *= np.sqrt(j)
                else:
                    partial /= np.sqrt(j)
                score += partial
        if capacity - item < 0.05 * capacity:
            score *= 2
        elif capacity - item < 0.2 * capacity:
            score *= 1.3
        else:
            for k in range(1, 4):
                if ratio < 0.3 * k:
                    score += k * np.sin(ratio * np.pi * k)
                else:
                    score -= k * np.cos(ratio * np.pi / (k + 1))
        if score < 0:
            score = abs(score) * 0.5
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        max_priority = 1
    else:
        max_priority = np.max(finite_priorities)
    for i in range(len(priorities)):
        if priorities[i] == np.inf:
            priorities[i] = max_priority * 3
    return priorities
